import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { Trash2, Store, Plus, X, Search, Edit2 } from 'lucide-react';

// Icono por defecto de Leaflet
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';
let DefaultIcon = L.icon({
    iconUrl: markerIcon,
    shadowUrl: markerShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});
L.Marker.prototype.options.icon = DefaultIcon;

function ChangeView({ center }) {
  const map = useMap();
  map.setView(center, 16);
  return null;
}

const Dashboard = () => {
  const navigate = useNavigate();
  const [locales, setLocales] = useState([
    { id: 1, nombre: "Local de Prueba", direccion: "Tucumán, Argentina", coords: [-26.816, -65.230] }
  ]);
  
  const [showModal, setShowModal] = useState(false);
  const [formLocal, setFormLocal] = useState({ nombre: '', direccion: '', coords: [-26.816, -65.216] });

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 75px)', background: '#f8fafc' }}>
      <div style={{ width: '400px', padding: '25px', background: 'white', borderRight: '1px solid #e2e8f0' }}>
        <h2>Mis Locales</h2>
        {locales.map(local => (
          <div key={local.id} style={{ padding: '15px', background: '#fff9f5', borderRadius: '12px', marginBottom: '10px' }}>
            <strong>{local.nombre}</strong>
            <p style={{ fontSize: '0.8rem', color: '#64748b', margin: '5px 0' }}>{local.direccion}</p>
            <button 
              onClick={() => navigate(`/ofertas/${local.id}`)}
              style={{ background: '#e67e22', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '5px', cursor: 'pointer' }}
            >
              Cargar Ofertas
            </button>
          </div>
        ))}
        <button onClick={() => setShowModal(true)} style={{ width: '100%', padding: '12px', background: '#1e293b', color: 'white', borderRadius: '10px', border: 'none', cursor: 'pointer', marginTop: '20px' }}>
          + Nueva Sucursal
        </button>
      </div>

      <div style={{ flex: 1 }}>
        <MapContainer center={[-26.816, -65.230]} zoom={14} style={{ height: '100%', width: '100%' }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {locales.map(local => (
            <Marker key={local.id} position={local.coords}>
              <Popup>{local.nombre}</Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>
    </div>
  );
};

export default Dashboard;
